parameters.text:
=You are an expert social media strategist and data analyst specializing in viral content prediction.

Analyze the following content submission and data signals, then return a structured JSON virality assessment.

---
CONTENT SUBMISSION:
Title: {{ $json.title }}
Body: {{ $json.body }}
Platform: {{ $json.platform }}
Content Type: {{ $json.content_type }}
Target Audience: {{ $json.target_audience }}
Has Media: {{ $json.has_media }}
Word Count: {{ $json.word_count }}
Proposed Publish Time: {{ $json.proposed_publish_time }}

---
HISTORICAL CONTEXT:
Total past posts analysed: {{ $json.historical_posts_count }}
Average engagement rate: {{ $json.avg_historical_engagement }}
Top performing posts (sample): {{ JSON.stringify($json.top_posts.slice(0,3)) }}

---
CURRENT SIGNALS:
Trend Index (0–100, higher=more trending): {{ $json.trend_index }}
Audience Peak Hours: {{ JSON.stringify($json.peak_hours) }}
Audience Sentiment Index (0–1): {{ $json.sentiment_index }}
Top Performing Formats Right Now: {{ JSON.stringify($json.top_formats) }}

---
PLATFORM CONFIG:
{{ JSON.stringify($json.platform_config) }}

SCORING WEIGHTS:
{{ JSON.stringify($json.scoring_weights) }}

---
Return ONLY a valid JSON object (no markdown, no explanation outside the JSON) with this exact structure:
{
  "virality_score": <integer 0-100>,
  "score_tier": <"HIGH" | "MODERATE" | "LOW">,
  "component_scores": {
    "trend_alignment": <0-100>,
    "engagement_prediction": <0-100>,
    "timing_score": <0-100>,
    "historical_similarity": <0-100>,
    "media_bonus": <0-100>
  },
  "key_drivers": [<list of 3-5 top factors driving the score, strings>],
  "pattern_matches": [<list of 2-3 historical patterns this content matches, strings>],
  "weaknesses": [<list of 1-3 things lowering the score, strings>],
  "recommendations": [<list of 2-4 specific actionable improvements, strings>],
  "best_publish_time": <ISO 8601 datetime string for optimal posting>,
  "predicted_engagement_range": { "low": <float>, "high": <float> },
  "confidence": <"HIGH" | "MEDIUM" | "LOW">
}

parameters.jsCode:
const item = $input.item.json;
let parsed = {};

try {
  const raw = item.output || item.response || item.text || '{}';
  const cleaned = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  // Fallback defaults if AI response parse fails
  parsed = {
    virality_score: 50,
    score_tier: 'MODERATE',
    component_scores: { trend_alignment: 50, engagement_prediction: 50, timing_score: 50, historical_similarity: 50, media_bonus: 50 },
    key_drivers: ['Unable to parse AI response — using defaults'],
    pattern_matches: [],
    weaknesses: ['AI response parse error'],
    recommendations: ['Re-run analysis or check AI node output'],
    best_publish_time: new Date().toISOString(),
    predicted_engagement_range: { low: 0.01, high: 0.03 },
    confidence: 'LOW'
  };
}

const score = parsed.virality_score ?? 50;
const tier = score >= 75 ? 'HIGH' : score >= 40 ? 'MODERATE' : 'LOW';

return {
  json: {
    ...item,
    ...parsed,
    virality_score: score,
    score_tier: tier,
    analysis_timestamp: new Date().toISOString(),
    scored_submission_id: item.submission_id
  }
};

